-- TRILHA: SEGURANÇA & COMPLIANCE
SET @security_id = (SELECT id FROM courses WHERE title = 'Segurança & Compliance' LIMIT 1);

INSERT INTO modules (course_id, title) VALUES (@security_id, 'Fundamentos de Segurança');
SET @security_mod1 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content) VALUES
(@security_mod1, 'OWASP Top 10', '<h2>OWASP Top 10</h2><ol><li>Injection (SQL, Command, LDAP)</li><li>Broken Authentication</li><li>Sensitive Data Exposure</li><li>XML External Entities (XXE)</li><li>Broken Access Control</li><li>Security Misconfiguration</li><li>Cross-Site Scripting (XSS)</li><li>Insecure Deserialization</li><li>Using Components with Known Vulnerabilities</li><li>Insufficient Logging & Monitoring</li></ol>'),
(@security_mod1, 'Princípios de Segurança', '<h2>Princípios CIA</h2><h3>Confidentiality</h3><p>Dados só acessíveis por pessoas autorizadas</p><h3>Integrity</h3><p>Dados não podem ser alterados sem autorização</p><h3>Availability</h3><p>Dados devem estar disponíveis quando necessário</p>'),
(@security_mod1, 'Defesa em Profundidade', '<h2>Defesa em Profundidade</h2><p>Não confie em uma única camada de segurança</p><ul><li>Firewall</li><li>Autenticação</li><li>Criptografia</li><li>Logging</li><li>Monitoramento</li></ul>');

INSERT INTO modules (course_id, title) VALUES (@security_id, 'Criptografia');
SET @security_mod2 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content) VALUES
(@security_mod2, 'Criptografia Simétrica', '<h2>Criptografia Simétrica</h2><p>Mesma chave para criptografar e descriptografar</p><h3>AES (Advanced Encryption Standard)</h3><p>Padrão atual, 128, 192 ou 256 bits</p><h3>DES/3DES</h3><p>Legado, não recomendado para novos projetos</p>'),
(@security_mod2, 'Criptografia Assimétrica', '<h2>Criptografia Assimétrica</h2><p>Chave pública para criptografar, chave privada para descriptografar</p><h3>RSA</h3><p>Amplamente usado, baseado em fatoração</p><h3>ECC (Elliptic Curve Cryptography)</h3><p>Mais eficiente que RSA</p>'),
(@security_mod2, 'Hashing e Funções Hash', '<h2>Hashing</h2><p>Função unidirecional que gera hash de dados</p><h3>MD5/SHA1</h3><p>Quebrados, não use para senhas</p><h3>SHA-256/SHA-512</h3><p>Seguros para dados</p><h3>bcrypt/Argon2</h3><p>Ideais para senhas (lento por design)</p>');

INSERT INTO modules (course_id, title) VALUES (@security_id, 'Autenticação & Autorização');
SET @security_mod3 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content) VALUES
(@security_mod3, 'OAuth 2.0', '<h2>OAuth 2.0</h2><p>Protocolo de autorização, não de autenticação</p><h3>Fluxo Authorization Code</h3><p>Mais seguro para aplicações web</p><h3>Fluxo Implicit</h3><p>Para SPAs, menos seguro</p>'),
(@security_mod3, 'JWT (JSON Web Tokens)', '<h2>JWT</h2><p>Token contém informações do usuário</p><h3>Estrutura</h3><p>Header.Payload.Signature</p><h3>Vantagens</h3><p>Stateless, escalável, mobile-friendly</p>'),
(@security_mod3, 'SAML vs OAuth vs OpenID Connect', '<h2>Comparação</h2><h3>SAML</h3><p>Enterprise, XML-based, autenticação</p><h3>OAuth</h3><p>Autorização, delegação</p><h3>OpenID Connect</h3><p>Camada de autenticação sobre OAuth</p>');

SELECT COUNT(*) as total_security FROM lessons WHERE module_id IN (SELECT id FROM modules WHERE course_id = @security_id);

